const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

app.post('/verify-nin', async (req, res) => {
  const { nin } = req.body;

  const baseUrl = process.env.PREMBLY_BASE_URL || 'https://api.prembly.com';
  const appId = process.env.PREMBLY_APP_ID;
  const apiKey = process.env.PREMBLY_API_KEY;

  const url = `${baseUrl}/verification/nin`;

  let retries = 0;
  let delay = 100;

  while (retries <= 3) {
    try {
      const response = await axios.post(url, { nin }, {
        headers: {
          'app-id': appId || '',
          'x-api-key': apiKey || ''
        }
      });
      return res.status(200).json(response.data);
    } catch (error) {
      if (error.response && error.response.status === 429) {
        if (retries === 3) {
          return res.status(429).json("Rate limit exceeded, please try again later");
        }
        await sleep(delay);
        delay *= 2;
        retries++;
      } else {
        const statusCode = error.response ? error.response.status : 500;
        const errorData = error.response ? error.response.data : { error: 'Internal Server Error' };
        return res.status(statusCode).json(errorData);
      }
    }
  }
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

